var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕이시여.","JPN":"王よ。","ENG":"My queen.","TWN":"王啊，"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"거대한 방주가 세월을 거슬러, 당신의 낙원을 짓밟기 위해 맹진해오고 있나이다.","JPN":"巨大な箱舟が時を遡り、あなたの楽園を踏みにじるために猛進してきております。","ENG":"A massive Ark is surging back through time, charging straight toward your paradise to trample it.","TWN":"一艘巨大的方舟正逆流歲月而來，即將踐踏你的樂園。"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"파노라마 위에 안배해 둔 실이 끊어졌더군요.","JPN":"パノラマの上に仕掛けておいた糸が切れていました。","ENG":"The thread I had arranged upon the Panorama has been severed.","TWN":"我在全景上安排的那條線被切斷了。"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아스모데우스의 짓이겠죠. 그 실을 태울 수 있는 건 그녀의 불꽃 뿐이니까.","JPN":"アスモデウスの仕業でしょう。あの糸を燃やせるのは彼女の炎だけですから。","ENG":"It must be Asmodeus' doing. Only her flames could burn that thread.","TWN":"應該是阿斯蒙蒂斯做的吧，只有她的火焰能燒斷那條線。"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"신임할 수 없는 자입니다. 방만하고 호전적이지요.","JPN":"信用できない者です。放漫かつ好戦的すぎます。","ENG":"She is not someone to be trusted. Careless and belligerent.","TWN":"那個人並不值得信任，性情散漫又好戰。"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 발키리의 숙적이기도 하죠.","JPN":"ですが、ヴァルキリーの宿敵でもあります。","ENG":"But she is also the Valkyrie's nemesis.","TWN":"但她同時也是女武神的宿敵。"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제가 그자에게 바라는 건 한 가지 뿐이에요.","JPN":"私があの者に望むのはただ一つだけです。","ENG":"There is only one thing I ask of her.","TWN":"我對那個人只抱有一個期待。"},"stage":{"bg":"MIND","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 뒤에 남는 것은... 모두 제가 감내해야 할 테니까요.","JPN":"後はすべて……私が受け入れるべきものですから。","ENG":"As for what follows after that... I will bear it all myself.","TWN":"至於之後留下的一切……都必須由我來承受。"},"stage":{"bg":"VOID","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐지?!","JPN":"何だ！？","ENG":"What was that?!","TWN":"什麼？！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"터널 진로로부터 고강도 차원압 발생!","JPN":"トンネル進路方向より高強度の次元圧発生！","ENG":"High-intensity dimensional pressure detected from the tunnel's route!","TWN":"隧道航線上出現高強度次元壓力！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"방금 충격으로 동행 중이던 수송선 1기가 대파됐습니다!","JPN":"今の衝撃で、同行していた輸送船1隻が大破しました！","ENG":"One of the transport ships accompanying us has just been destroyed by the impact!","TWN":"剛才的衝擊讓同行的一艘運輸船完全毀壞！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그건 뭐였죠? 너무 순식간이라 보이지도 않았는데?!","JPN":"あれは何だったんですか？　一瞬すぎて何も見えませんでしたが！？","ENG":"What was that? It happened so fast I couldn't even see it!","TWN":"那是什麼？太快了，根本看不見？！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"...차원압 발생지의 에너지 형태를 분석해 이미지화하는 중.","JPN":"……次元圧発生地のエネルギー形態を分析し、画像化中。","ENG":"...Analyzing the energy form at the dimensional pressure source and converting it into an image.","TWN":"……正在分析次元壓力來源的能量形態並進行影像化。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저건... 인형 팔이잖아?","JPN":"あれは……人形の腕？","ENG":"That's... a doll's arm?","TWN":"那不是……人偶的手臂嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...타기리온. 그 녀석이 개입하기 시작한 거야.","JPN":"……タギリオン。あいつが介入し出したんだ。","ENG":"...Thagirion. She's started to interfere.","TWN":"……塔基里翁，那傢伙開始介入了。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다시 옵니다! 저희 함선을 노리고 있어요!","JPN":"もう一度来ます！　私たちの艦船を狙っています！","ENG":"It's coming again! It's targeting our ship!","TWN":"又來了！目標是我們的艦船！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"회피 기동이 가능한 수준이 아니잖아, 이건!","JPN":"回避起動ができるレベルじゃないよ、これは！","ENG":"This isn't something we can evade with normal maneuvering!","TWN":"這根本閃避不了吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"꺄아앗?!","JPN":"きゃああっ！？","ENG":"Kyaah?!","TWN":"呀啊？！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_03"},{"id":"L26_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"방금 뭐였죠? 저희 함선의 좌표가... 잠시 바뀐 건가요?","JPN":"今のは？　この艦船の座標が……一瞬変わった？","ENG":"What was that just now? Our ship's coordinates... did they change for a moment?","TWN":"剛剛那是什麼？我們的艦船座標……好像突然改變了？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"놀라게 했다면 미안하군.","JPN":"すまない、驚かせてしまったか。","ENG":"My apologies if that startled you.","TWN":"抱歉嚇到你們了。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"가르강튀아가 차원통로에서도 잘 작동해줘서 다행이야.","JPN":"ガルガンティアが次元通路でも上手く動いてくれてよかった。","ENG":"I'm glad Garguantia is functioning well even within the dimensional passage.","TWN":"幸好加爾剛迪亞在次元通道裡也能正常運作。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마리아 아줌마!","JPN":"マリアおばさん！","ENG":"Maria!","TWN":"瑪麗亞阿姨！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"델타세븐 분들이 지원을 온 건가요?","JPN":"デルタセブンの方々が応援に来てくださったんですか？","ENG":"Has Delta Seven come to support us?","TWN":"第七三角洲部隊的人來支援了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"더 많은 수를 기대했다면 유감일세. 자네가 아는 얼굴들 중엔 나 뿐일 거야.","JPN":"もっと大人数を期待したなら、謝っておこう。君の見知った顔はおそらく私だけだ。","ENG":"If you were expecting more, I'm afraid I'm the only familiar face you'll see.","TWN":"如果你們期待更多人，那可要失望了。你認識的人大概只有我。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"따라오겠다고 고집 부리는 녀석도 있었지만... 누군가는 우리가 돌아갈 고향을 지켜야 하니 말이지.","JPN":"ついて来ると意地を張る奴もいたが……誰かは私たちの帰る場所を守らねばならないからな。","ENG":"There were others who insisted on coming along... but someone has to guard the place we must return to.","TWN":"雖然也有人堅持要跟來……但總得有人守著我們要回去的地方。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그러니, 화력 지원은 어렵지만- 자네들이 이 난관을 무사히 피할 수 있도록 도움을 주러 왔네.","JPN":"だから、火力支援は難しいが……君たちがこの難関を無事に乗り越えられるよう、力を貸しに来た。","ENG":"So while I can't provide fire support, I came to help ensure you can safely avoid this danger.","TWN":"所以雖然無法提供火力支援－但我會幫你們避開這場危機。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"굉장해. 뭔가 날아올 때마다 차원함선의 공간좌표가 변하고 있어.","JPN":"すごい、何かが飛んでくるたびに次元艦船の空間座標が変化してる。","ENG":"Amazing. Every time something flies toward us, the dimensional ship's spatial coordinates keep shifting.","TWN":"好厲害。每當有東西飛來，次元艦船的空間座標就會改變。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 피하는 것만으론 한계가 있어 보여. 우리가 출격하는 게 좋지 않을까?","JPN":"でも避けるだけじゃ、じきに限界がくるよ。私たちが出撃したほうがいいんじゃない？","ENG":"But it looks like there's a limit to how long we can keep dodging. Wouldn't it be better if we deploy?","TWN":"但光靠閃避似乎有極限，我們是不是該出擊？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"초공간돌파 상태에서 밖으로 나가는 건 죽겠다는 소리다.","JPN":"超空間突破状態で外に出るのは自殺行為だ。","ENG":"Going outside while in a hyperspace breakthrough state is the same as asking to die.","TWN":"在超空間突破狀態下出去等於找死。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설령 버틴다 해도 그런 환경에서 제대로 싸울 수 있을 턱이 없지.","JPN":"耐えられたとしても、そんな環境でまともに戦えるわけがない。","ENG":"Even if you could endure it, there's no way you could fight properly in that kind of environment.","TWN":"就算撐得住，也不可能在那種環境下好好戰鬥。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이런 환경에도 제약을 받지 않고 싸울 수 있는 예외 케이스가-","JPN":"こんな環境下でも制約を受けずに戦える例外ケースが……","ENG":"But there are cases. Not many, but some exceptions who can fight without being restricted...","TWN":"不過其實並不是完全沒有－。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아주 없는 건 아니죠.","JPN":"まったくないわけではなりません。","ENG":"By an environment like this.","TWN":"能在這種環境下戰鬥的例外。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...그럼, 부탁하지.","JPN":"……では、頼む。","ENG":"...Then I'll leave it to you.","TWN":"……那就拜託了。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"예, 관리자님.","JPN":"はい、管理者様。","ENG":"Yes, Administrator.","TWN":"是，管理者。"},"stage":{"bg":"VOID","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L2_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"전원 전투 준비. 그림자 공간을 전개한다.","JPN":"全員戦闘準備。シャドウ空間を展開する。","ENG":"All personnel, prepare for combat. Deploy the Shadow Space.","TWN":"全員準備戰鬥。暗影空間，展開。"},"stage":{"bg":"VOID","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"목표는 차원함선을 노리고 숨어든 꼭두각시 인형...!","JPN":"目標は次元艦船を狙って忍び込んだ操り人形……！","ENG":"The target is the puppet doll that has slipped in while aiming for the dimensional ship...!","TWN":"目標是潛伏襲擊次元艦船的傀儡人偶……！"},"stage":{"bg":"VOID","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"클리파 영역에서 튀어나오는 순간, 화력을 집중하라!","JPN":"クリファ領域から飛び出た瞬間、火力を集中せよ！","ENG":"The moment it emerges from the Qlipha domain, concentrate fire!","TWN":"一旦它從逆卡巴拉領域現身，集中火力攻擊！"},"stage":{"bg":"VOID","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식 에너지를 응집시킨... 포격이라고?","JPN":"侵食エネルギーを凝集した……砲撃だと？","ENG":"A bombardment... condensed Corruption energy?","TWN":"侵蝕能量凝聚而成的……炮擊？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_UI_WARFARE_EXPLOSION_BIG"},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그림자가 저 정도의 응용력을 가진다는 건, 지성을 가지고 사고한다는 뜻인가?","JPN":"シャドウにあのレベルの応用ができるってことは、知性を持って思考してるってことか？","ENG":"If Shadows are capable of adapting their tactics to that extent, does it mean they possess intelligence and can think?","TWN":"暗影居然有這種應用能力，代表它具備智慧嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사고하는 정도가 아니죠.","JPN":"思考するレベル以上です。","ENG":"It's more than just thinking.","TWN":"不只是能思考而已。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그녀는 관리국에서 포격술이 가장 뛰어난 메이즈 전대니까요.","JPN":"彼女は管理局でも最も優れた砲撃術を駆使するメイズ戦隊ですから。","ENG":"She's the Maze Division's finest artillery specialist in the Administration.","TWN":"她可是管理局中砲擊技術最強的梅茲戰隊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"통했다! 팔을 부쉈어!","JPN":"効いた！　腕を壊したよ！","ENG":"It worked! We broke its arm!","TWN":"命中了！手臂被打斷了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만... 팔의 갯수도 계속해서 늘어나는군요.","JPN":"ですが……腕の数も増え続けていますよ。","ENG":"But... the number of arms keeps increasing.","TWN":"但是……手臂的數量還在增加。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"외부로부터 그림자 개체 다수 포착...! 함선 쪽으로 빠르게 접근 중!","JPN":"外部より多数のシャドウ個体を捕捉……！　艦船に向かって高速接近中！","ENG":"Multiple Shadows detected approaching from outside...! They're rapidly closing in on the ship!","TWN":"外部偵測到大量暗影個體……！正快速接近艦船中！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그림자 다수라고? 여럿이 뭉친 것도 모자라 차원통로에 무슨 수로 접근한 거지?","JPN":"多数のシャドウだと？　群れを成しているだけでも驚きだが、次元通路にはどうやって近づいたんだ？","ENG":"Multiple Shadows? Even setting aside how many there are, how did they manage to approach the dimensional passage?","TWN":"暗影有這麼多？不只是聚在一起而已，它們到底是怎麼接近次元通道的？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_ON","text":{"KOREA":"앗, 저거에요! 소대장님을 방해하던 그 실! 저 그림자들 몸에도 이어져 있어요!","JPN":"あっ、あれです！　小隊長を邪魔してたあの糸！　あのシャドウたちの体にもついてます！","ENG":"Ah, that's it! Those threads that were interfering with Commander! They're connected to those Shadows too!","TWN":"啊，就是那個！之前妨礙小隊長的那條線！那些暗影身上也連著一樣的線！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_MAIN_NPC_ON","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"타기리온에게 조종 당하는 녀석들이군.","JPN":"タギリオンに操られている奴らか。","ENG":"They're being controlled by Thagirion.","TWN":"是被塔基里翁操控的傢伙們啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_MAIN_NPC_ON","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"팔을 막고 있는 류드밀라의 부대가 저 많은 그림자들까지 감당하는 건 벅찰 거다.","JPN":"腕を食い止めているリュドミラの部隊に、あの数のシャドウの相手までさせるのは無理だ。","ENG":"The unit led by Lyudmila that's holding back the arms won't be able to handle that many Shadows as well.","TWN":"正在牽制手臂的盧德米拉部隊，恐怕無法同時應付那麼多暗影。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_MAIN_NPC_ON","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"안토노프 중장, 가르강튀아로 저 그림자들을 우리의 사정권까지 끌어올 수 있겠나?","JPN":"アントノフ中将、ガルガンティアであのシャドウたちを我々の射程圏内まで連れてこられるか？","ENG":"Lieutenant General Antonov, can Garguantia pull those Shadows into our firing range?","TWN":"安東諾夫中將，能使用加爾剛迪亞把那些暗影拉進我們的射程範圍嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"괜찮으시겠습니까? 그렇게 하면 코핀함 역시 그림자의 공격에 노출될 겁니다.","JPN":"いいのですか？　そうするとコフィン艦もシャドウの攻撃に晒されてしまいます。","ENG":"Are you certain? If we do that, Coffin will be exposed to their attacks as well.","TWN":"這樣真的沒問題嗎？如果這麼做，科芬艦也會暴露在暗影的攻擊下。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희에게 맡겨주시죠.","JPN":"私たちにお任せください。","ENG":"Leave that to us.","TWN":"交給我們吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"난동 부릴 틈도 주지 않을 테니까요.","JPN":"暴れる隙も与えませんので。","ENG":"We won't even give them the chance to run wild.","TWN":"我們不會讓它們有機會胡鬧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그렇다면, 무운을 빌겠습니다.","JPN":"ならば、ご武運を祈りましょう。","ENG":"In that case, I wish you good fortune.","TWN":"那就祝你們好運了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};